import{_ as r,c as a,o,ae as t}from"./chunks/framework.DN7zo1cr.js";const p="/images/DeepSeekProxy.png",s="/images/cross_s1.png",i="/images/cross_s2.png",P=JSON.parse('{"title":"DeepSeekProxy","description":"","frontmatter":{},"headers":[],"relativePath":"home/DeepSeek.md","filePath":"home/DeepSeek.md"}'),l={name:"home/DeepSeek.md"};function n(c,e,k,_,d,h){return o(),a("div",null,e[0]||(e[0]=[t('<h1 id="deepseekproxy" tabindex="-1">DeepSeekProxy <a class="header-anchor" href="#deepseekproxy" aria-label="Permalink to &quot;DeepSeekProxy&quot;">​</a></h1><blockquote><p>✨在1.61以上的版本中，插件支持调用DeepSeek的API进行答案解析<br> 🔓每个用户每日有50次的限额，在不使用DeepSeekProxy的情况下<br> 🖥️如果想使用自己的API Key，需要自行搭建DeepSeekProxy</p></blockquote><h2 id="_1️⃣获取api-key" tabindex="-1">1️⃣获取API Key <a class="header-anchor" href="#_1️⃣获取api-key" aria-label="Permalink to &quot;1️⃣获取API Key&quot;">​</a></h2><p><a href="./GetAPIKey">点击查看教程</a></p><h2 id="_2️⃣下载并运行deepseekproxy" tabindex="-1">2️⃣下载并运行DeepSeekProxy <a class="header-anchor" href="#_2️⃣下载并运行deepseekproxy" aria-label="Permalink to &quot;2️⃣下载并运行DeepSeekProxy&quot;">​</a></h2><ul><li><a href="https://wwyl.lanzouv.com/b00ocrzzje" target="_blank" rel="noreferrer">蓝奏云</a> 密码：43so</li><li><a href="https://gitee.com/m0zey/DeepSeekProxy/releases" target="_blank" rel="noreferrer">Gitee</a> 下载.7z文件</li></ul><p><img src="'+p+'" alt="images/DeepSeekProxy.png"> 填入相应平台的API Key点击保存即可</p><h2 id="_3️⃣为什么需要deepseekproxy" tabindex="-1">3️⃣为什么需要DeepSeekProxy？ <a class="header-anchor" href="#_3️⃣为什么需要deepseekproxy" aria-label="Permalink to &quot;3️⃣为什么需要DeepSeekProxy？&quot;">​</a></h2><p>因为目前所有的API都是不能跨域的，也就是说不能在一个网站中进行请求,所以需要搭建<code>代理服务器</code>。 <img src="'+s+'" alt="浏览器拦截"><img src="'+i+'" alt="浏览器拦截"></p><p>由于插件是公益性质的，难以承担高性能服务器产生费用，如果使用我们目前的服务器资源搭建代理服务器，会造成极大的延迟与不稳定</p><p>同时，如果使用我们的服务器，在代理请求过程中会传递API密钥，一旦我们的服务器遭受攻击，难以保证用户数据的安全</p><p>因此，我们选择开发<code>DeepSeekProxy</code>，它是一个开源的代理服务器软件，源码发布在了<a href="https://gitee.com/m0zey/DeepSeekProxy" target="_blank" rel="noreferrer">Gitee</a>，它运行在你的电脑上，代理请求DeepSeek的API，转发AI生成的回答给在浙学网课助手。在运行过程中不会向我们在内的任何第三方网站传递密钥数据，保证了密钥安全</p>',12)]))}const y=r(l,[["render",n]]);export{P as __pageData,y as default};
